// =============================================================
// LocalRise Advisory - Cálculo de Elegibilidade para Follow-up
// =============================================================
// Calcula quantos dias se passaram desde a Data Proposta
// e marca o lead como elegível se >= 3 dias

const items = $input.all();
const hoje = new Date();
hoje.setHours(0, 0, 0, 0);

return items.map(item => {
  const dataProposta = item.json['Data Proposta'];
  let dataPropostaDate;

  if (!dataProposta || dataProposta.toString().trim() === '') {
    // Sem data registrada: não elegível, log de aviso
    console.warn(`[LocalRise] Lead sem Data Proposta: ${item.json['Nome Negócio']}`);
    return {
      ...item,
      json: {
        ...item.json,
        diasDesdeEnvio: -1,
        elegivel: false,
        motivoNaoElegivel: 'Data Proposta não preenchida'
      }
    };
  }

  // Suporta formatos: DD/MM/YYYY, DD-MM-YYYY e YYYY-MM-DD
  const dataStr = dataProposta.toString().trim();
  if (dataStr.match(/^\d{2}[\/\-]\d{2}[\/\-]\d{4}$/)) {
    const sep = dataStr.includes('/') ? '/' : '-';
    const [dia, mes, ano] = dataStr.split(sep);
    dataPropostaDate = new Date(parseInt(ano), parseInt(mes) - 1, parseInt(dia));
  } else if (dataStr.match(/^\d{4}-\d{2}-\d{2}/)) {
    dataPropostaDate = new Date(dataStr);
  } else {
    // Tenta parsear qualquer outro formato
    dataPropostaDate = new Date(dataStr);
  }

  if (isNaN(dataPropostaDate.getTime())) {
    console.error(`[LocalRise] Data inválida para lead ${item.json['Nome Negócio']}: ${dataProposta}`);
    return {
      ...item,
      json: {
        ...item.json,
        diasDesdeEnvio: -1,
        elegivel: false,
        motivoNaoElegivel: `Data inválida: ${dataProposta}`
      }
    };
  }

  dataPropostaDate.setHours(0, 0, 0, 0);
  const diffMs = hoje.getTime() - dataPropostaDate.getTime();
  const diasDesdeEnvio = Math.floor(diffMs / (1000 * 60 * 60 * 24));
  const elegivel = diasDesdeEnvio >= 3;

  console.log(`[LocalRise] ${item.json['Nome Negócio']} | ${diasDesdeEnvio} dias | Elegível: ${elegivel}`);

  return {
    ...item,
    json: {
      ...item.json,
      diasDesdeEnvio,
      elegivel,
      motivoNaoElegivel: elegivel ? null : `Apenas ${diasDesdeEnvio} dia(s) desde o envio`
    }
  };
});

// =============================================================
// LocalRise Advisory - Formatação da Mensagem de Follow-up
// =============================================================

const item = $input.first().json;

// Emojis de prioridade
const prioridadeEmoji = {
  'Alta': '🔴',
  'Média': '🟡',
  'Baixa': '🟢'
}[item['Prioridade']] || '⚪';

// Formata nota do Google com estrelas
const nota = parseFloat(item['Nota Google'] || 0);
const estrelas = nota > 0 ? `${nota} ⭐` : 'Sem avaliação';

// Urgência baseada em quantos dias passaram
let urgencia = '';
if (item.diasDesdeEnvio >= 7) {
  urgencia = '⚠️ *URGENTE - +7 dias sem resposta!*\n';
} else if (item.diasDesdeEnvio >= 5) {
  urgencia = '🚨 *ATENÇÃO - +5 dias sem resposta*\n';
}

const mensagem = `${urgencia}🔔 *FOLLOW-UP NECESSÁRIO*
━━━━━━━━━━━━━━━━━━━━━
🏢 *${item['Nome Negócio'] || 'N/A'}*
${prioridadeEmoji} Prioridade: *${item['Prioridade'] || 'N/A'}*

📞 Telefone: ${item['Telefone'] || 'Não informado'}
🌐 Site: ${item['Site'] || 'Não informado'}
📸 Instagram: ${item['Instagram'] || 'Não informado'}

📊 *Perfil Google:*
   • Nota: ${estrelas}
   • Reviews: ${item['Qtd Reviews'] || '0'}

📅 Proposta enviada em: ${item['Data Proposta'] || 'N/A'}
⏰ Dias sem resposta: *${item.diasDesdeEnvio} dias*

✅ *Status será atualizado para: Follow-up 1*
━━━━━━━━━━━━━━━━━━━━━
_LocalRise Advisory • CRM Automático_`;

return [{
  json: {
    ...item,
    mensagemFormatada: mensagem,
    rowId: item['ID']
  }
}];

// Log para auditoria de leads ainda não elegíveis
const items = $input.all();

if (items.length === 0) {
  console.log('[LocalRise] Nenhum lead aguardando período de follow-up hoje.');
  return [];
}

console.log(`[LocalRise] ${items.length} lead(s) ainda no período de espera:`);
items.forEach(item => {
  console.log(`  - ${item.json['Nome Negócio']}: ${item.json.diasDesdeEnvio >= 0 ? item.json.diasDesdeEnvio + ' dia(s)' : item.json.motivoNaoElegivel}`);
});

return items;

// =============================================================
// LocalRise Advisory - Resumo da Execução
// =============================================================
// Este node consolida o resultado após a atualização do Sheets

const item = $input.first().json;

console.log(`[LocalRise] ✅ Follow-up processado com sucesso:`);
console.log(`  - Lead: ${item['Nome Negócio']}`);
console.log(`  - Dias desde proposta: ${item.diasDesdeEnvio}`);
console.log(`  - Status atualizado para: Follow-up 1`);
console.log(`  - Timestamp: ${new Date().toISOString()}`);

return [{ json: { ...item, processadoEm: new Date().toISOString(), novoStatus: 'Follow-up 1' } }];
